const b = msg.responseBuffer && msg.responseBuffer.buffer;
if (!b || b.length < 8) { node.error('Sem 8 bytes no responseBuffer'); return null; }
const buf = Buffer.from(b);
const wh = buf.readDoubleBE(0); // energia ativa em Wh
msg.payload = {
 ts: new Date().toISOString(),
 metric: 'energy_active_wh',
 wh: wh,
 kwh: wh/1000
};
return msg;

const b = msg.responseBuffer && msg.responseBuffer.buffer;
if (!b || b.length < 8) { node.error('Sem 8 bytes no responseBuffer'); return null; }
const buf = Buffer.from(b);
const varh = buf.readDoubleBE(0); // energia reativa em varh
msg.payload = {
 ts: new Date().toISOString(),
 metric: 'energy_reactive_varh',
 varh: varh,
 kvarh: varh/1000
};
return msg;

const d = msg.responseBuffer && msg.responseBuffer.data;
if (!d || d.length < 2) { node.error('Sem 2 regs para U32'); return null; }
// regs são 16-bit: [Hi, Lo] → U32
const hi = d[0] >>> 0;
const lo = d[1] >>> 0;
const u32 = (hi << 16) + lo;
msg.payload = { ts: new Date().toISOString(), metric: 'demand_length_s', seconds: u32 };
return msg;

const d = msg.responseBuffer && msg.responseBuffer.data;
