const p = msg.payload || {};

// Validações simples
if (!p.DateTime || !Number.isFinite(p.wh_total)) {
    node.error("Payload de consumo inválido (esperado DateTime + wh_total).", msg);
    return null;
}

// 1) Documento que será gravado no Mongo
const doc = {
    // Grava como Date real (Mongo registra como BSON Date)
    //  Se preferir guardar string ISO, troque por: DateTime: p.DateTime
    DateTime: new Date(p.DateTime),

    IDMaq: "SE03_MM01",               // ajuste para o ID da máquina que você quiser
    wh_total: Math.round(p.wh_total), // arredondar ou não, você escolhe
    kwh_intervalo: p.kwh_intervalo,   // pode ser null na primeira leitura, ok
    reset_flag: !!p.reset_flag,       // garante booleano

    // Campos extras se quiser:
    // fonte: "PAC3100",
    // observacao: "consumo intervalo 15min"
};

// 2) mongodb4 espera um array de argumentos → [doc]
msg.payload = [doc];

// 3) Define operação
msg.operation = "insertOne";

// 4) (Opcional) define coleção por mensagem
//    Comente essa linha se preferir setar a coleção direto no nó mongodb4
msg.collection = "AMG_Consumo";   // ou "AMG_EnergyData", como você preferir

return msg;

